var items = $input.all();
var contentDraft = [];
var analyse = [];
var gliederung = [];
var spreadsheetId = '';

try {
  contentDraft = $('Sheets — Content Draft lesen').all().map(function(i) { return i.json; });
} catch(e) { contentDraft = []; }
try {
  analyse = $('Sheets — Analyse lesen').all().map(function(i) { return i.json; });
} catch(e) { analyse = []; }
try {
  gliederung = $('Sheets — Gliederung lesen').all().map(function(i) { return i.json; });
} catch(e) { gliederung = []; }
try {
  spreadsheetId = $('WF7 Variablen').first().json.spreadsheet_id;
} catch(e) { spreadsheetId = ''; }

var fullArticle = contentDraft
  .map(function(row) { return '## ' + (row.abschnitt || '') + '\n' + (row.content_raw || ''); })
  .join('\n\n');

var commodityTopics = analyse
  .filter(function(a) { return a.kategorie === 'commodity' || a.analyse_typ === 'commodity_check'; })
  .map(function(a) { return a.keyword_oder_thema || a.details || ''; })
  .filter(function(t) { return t.length > 0; });

var uniqueAngles = analyse
  .filter(function(a) { return a.kategorie === 'unique_angle' || a.analyse_typ === 'unique_angle'; })
  .map(function(a) { return a.keyword_oder_thema || a.details || ''; })
  .filter(function(t) { return t.length > 0; });

var allTopics = commodityTopics.length > 0 ? commodityTopics : analyse.map(function(a) { return a.keyword_oder_thema || ''; }).filter(function(t) { return t.length > 0; });
var allAngles = uniqueAngles.length > 0 ? uniqueAngles : analyse.filter(function(a) { return a.score && parseFloat(a.score) > 70; }).map(function(a) { return a.details || a.keyword_oder_thema || ''; }).filter(function(t) { return t.length > 0; });

var result = {
  spreadsheet_id: spreadsheetId,
  full_article: fullArticle,
  sections: JSON.stringify(contentDraft),
  commodity_topics: JSON.stringify(allTopics.slice(0, 10)),
  unique_angles: JSON.stringify(allAngles.slice(0, 10)),
  gliederung: JSON.stringify(gliederung)
};

return [{json: result}];

var items = $input.all();
var voyageResponse = $input.first().json;
var prevData = null;
try {
  prevData = $('QA Daten vorbereiten').first().json;
} catch(e) { prevData = {}; }

var rawData = (voyageResponse.data || []);
var embeddings = rawData.map(function(d) { return d.embedding; });

if (embeddings.length < 2) {
  var fallback = {
    coverage_score: 0,
    topic_scores: '[]',
    low_coverage_topics: 'Keine Embeddings erhalten',
    spreadsheet_id: prevData.spreadsheet_id || '',
    full_article: prevData.full_article || '',
    sections: prevData.sections || '[]',
    gliederung: prevData.gliederung || '[]'
  };
  return [{json: fallback}];
}

function cosineSim(a, b) {
  var dot = 0, normA = 0, normB = 0;
  for (var idx = 0; idx < a.length; idx++) {
    dot += a[idx] * b[idx];
    normA += a[idx] * a[idx];
    normB += b[idx] * b[idx];
  }
  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

var articleEmbedding = embeddings[0];
var topicEmbeddings = embeddings.slice(1);

var commodityTopics = JSON.parse(prevData.commodity_topics || '[]');
var uniqueAngles = JSON.parse(prevData.unique_angles || '[]');
var allTopicLabels = [].concat(commodityTopics, uniqueAngles);

var topicScores = topicEmbeddings.map(function(emb, idx) {
  var label = allTopicLabels[idx] || ('Topic ' + String(idx + 1));
  var sim = Math.round(cosineSim(articleEmbedding, emb) * 100) / 100;
  return { topic: label, similarity: sim };
});

var totalSim = 0;
for (var ts = 0; ts < topicScores.length; ts++) {
  totalSim += topicScores[ts].similarity;
}
var avgScore = topicScores.length > 0 ? Math.round(totalSim / topicScores.length * 100) : 0;

var lowParts = [];
for (var lc = 0; lc < topicScores.length; lc++) {
  if (topicScores[lc].similarity < 0.5) {
    lowParts.push(topicScores[lc].topic + ' (' + topicScores[lc].similarity + ')');
  }
}
var lowCoverage = lowParts.length > 0 ? lowParts.join(', ') : 'Alle Themen gut abgedeckt';

var output = {
  coverage_score: avgScore,
  topic_scores: JSON.stringify(topicScores),
  low_coverage_topics: lowCoverage,
  spreadsheet_id: prevData.spreadsheet_id || '',
  full_article: prevData.full_article || '',
  sections: prevData.sections || '[]',
  gliederung: prevData.gliederung || '[]'
};

return [{json: output}];

var items = $input.all();

function extractText(response) {
  if (response && response.content && response.content[0] && response.content[0].text) {
    return response.content[0].text;
  }
  if (response && response.data && response.data[0] && response.data[0].content && response.data[0].content[0] && response.data[0].content[0].text) {
    return response.data[0].content[0].text;
  }
  return '';
}

function parseJSON(text) {
  if (!text) return null;
  try {
    return JSON.parse(text);
  } catch(e) {
    var mdMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (mdMatch) {
      try { return JSON.parse(mdMatch[1].trim()); } catch(e2) { /* ignore */ }
    }
    var objMatch = text.match(/\{[\s\S]*\}/);
    if (objMatch) {
      try { return JSON.parse(objMatch[0]); } catch(e3) { /* ignore */ }
    }
    return null;
  }
}

var coverageData = {};
var spreadsheetId = '';
try {
  coverageData = $('Coverage Score berechnen').first().json;
  spreadsheetId = coverageData.spreadsheet_id || '';
} catch(e) { coverageData = {}; }

var humanizerRaw = '';
var voiceRaw = '';
var metaRaw = '';
var linkRaw = '';
var visualRaw = '';
try { humanizerRaw = extractText($('Claude — AI Humanizer').first().json); } catch(e) {}
try { voiceRaw = extractText($('Claude — Voice Checker').first().json); } catch(e) {}
try { metaRaw = extractText($('Claude — Meta Optimizer').first().json); } catch(e) {}
try { linkRaw = extractText($('Claude — Link Strategist').first().json); } catch(e) {}
try { visualRaw = extractText($('Claude — Visual Planner').first().json); } catch(e) {}

var humanizerData = parseJSON(humanizerRaw) || { sections: [] };
var voiceData = parseJSON(voiceRaw) || { sections: [], voice_check: { status: 'fehler', details: 'Parsing fehlgeschlagen', score: 0 } };
var metaData = parseJSON(metaRaw) || { meta_vorschlaege: [] };
var linkData = parseJSON(linkRaw) || { link_vorschlaege: [] };
var visualData = parseJSON(visualRaw) || { visual_vorschlaege: [] };

var qaResults = [];
qaResults.push({
  check_typ: 'content_coverage',
  status: (coverageData.coverage_score || 0) >= 60 ? 'bestanden' : 'nacharbeit',
  details: 'Coverage Score: ' + (coverageData.coverage_score || 0) + ' Prozent. Low Coverage: ' + (coverageData.low_coverage_topics || 'n/a'),
  score: coverageData.coverage_score || 0
});

if (voiceData.voice_check) {
  qaResults.push({
    check_typ: 'voice_check',
    status: voiceData.voice_check.status || 'unbekannt',
    details: voiceData.voice_check.details || '',
    score: voiceData.voice_check.score || 0
  });
}

var humSections = humanizerData.sections || [];
qaResults.push({
  check_typ: 'ai_humanizer',
  status: humSections.length > 0 ? 'bestanden' : 'fehler',
  details: humSections.length + ' Abschnitte humanisiert',
  score: humSections.length > 0 ? 85 : 0
});

var metaVorschlaege = metaData.meta_vorschlaege || [];
qaResults.push({
  check_typ: 'meta_optimization',
  status: metaVorschlaege.length > 0 ? 'bestanden' : 'fehler',
  details: metaVorschlaege.length + ' Meta-Vorschlaege generiert',
  score: metaVorschlaege.length >= 3 ? 90 : 50
});

var linkVorschlaege = linkData.link_vorschlaege || [];
qaResults.push({
  check_typ: 'link_strategie',
  status: linkVorschlaege.length > 0 ? 'bestanden' : 'fehler',
  details: linkVorschlaege.length + ' Link-Vorschlaege generiert',
  score: linkVorschlaege.length >= 3 ? 85 : 40
});

var visualVorschlaege = visualData.visual_vorschlaege || [];
qaResults.push({
  check_typ: 'visual_planung',
  status: visualVorschlaege.length > 0 ? 'bestanden' : 'fehler',
  details: visualVorschlaege.length + ' Visual-Vorschlaege generiert',
  score: visualVorschlaege.length >= 2 ? 80 : 30
});

var metaLinksResults = [];
for (var mi = 0; mi < metaVorschlaege.length; mi++) {
  var m = metaVorschlaege[mi];
  metaLinksResults.push({ typ: m.typ || 'meta', vorschlag: m.vorschlag || '', position_im_text: m.position_im_text || '', ziel_url: m.ziel_url || '' });
}
for (var li = 0; li < linkVorschlaege.length; li++) {
  var lnk = linkVorschlaege[li];
  metaLinksResults.push({ typ: lnk.typ || 'link', vorschlag: lnk.vorschlag || '', position_im_text: lnk.position_im_text || '', ziel_url: lnk.ziel_url || '' });
}
for (var vi = 0; vi < visualVorschlaege.length; vi++) {
  var vis = visualVorschlaege[vi];
  metaLinksResults.push({ typ: vis.typ || 'visual', vorschlag: vis.vorschlag || '', position_im_text: vis.position_im_text || '', ziel_url: vis.ziel_url || '' });
}

var contentUpdates = [];
var sections = JSON.parse(coverageData.sections || '[]');
var voiceSections = voiceData.sections || [];
for (var si = 0; si < sections.length; si++) {
  var section = sections[si];
  var humanized = humSections.find(function(s) { return s.abschnitt === section.abschnitt; });
  var voiced = voiceSections.find(function(s) { return s.abschnitt === section.abschnitt; });
  contentUpdates.push({
    abschnitt: section.abschnitt || '',
    content_humanized: (humanized && humanized.content_humanized) ? humanized.content_humanized : '',
    content_final: (voiced && voiced.content_final) ? voiced.content_final : ((humanized && humanized.content_humanized) ? humanized.content_humanized : '')
  });
}

var finalResult = {
  spreadsheet_id: spreadsheetId,
  qa_results: JSON.stringify(qaResults),
  meta_links_results: JSON.stringify(metaLinksResults),
  content_updates: JSON.stringify(contentUpdates)
};

return [{json: finalResult}];
